class MyAnimatedPainter extends CustomPainter {
  final double value;
  MyAnimatedPainter(this.value);

  @override
  void paint(Canvas canvas, Size size) {
    final Paint paint = Paint()..color = Colors.blue;
    canvas.drawCircle(Offset(size.width / 2, size.height / 2), value * 50, paint);
  }

  @override
  bool shouldRepaint(covariant MyAnimatedPainter oldDelegate) {
    return oldDelegate.value != value;
  }
}
